// Cloudflare Worker for SendGrid Email and Stripe Payment Integration

const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-API-Key',
  'Access-Control-Max-Age': '86400',
};

function validateApiKey(request, env) {
  const apiKey = request.headers.get('X-API-Key');
  if (!apiKey || apiKey !== env.WORKER_API_KEY) {
    return false;
  }
  return true;
}

function validateOrigin(request) {
  const origin = request.headers.get('Origin');
  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    return origin;
  }
  return null;
}

function sanitizeInput(input) {
  if (typeof input === 'string') {
    return input.trim().substring(0, 10000);
  }
  return input;
}

function validateEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

async function sendEmail(env, emailData) {
  const { to, subject, text, html } = emailData;

  if (!validateEmail(to)) {
    throw new Error('Invalid email address');
  }

  if (!subject || !text) {
    throw new Error('Subject and text are required');
  }

  const sendGridPayload = {
    personalizations: [
      {
        to: [{ email: sanitizeInput(to) }],
        subject: sanitizeInput(subject),
      },
    ],
    from: {
      email: env.SENDGRID_FROM_EMAIL,
      name: env.SENDGRID_FROM_NAME || 'Your App',
    },
    content: [
      {
        type: 'text/plain',
        value: sanitizeInput(text),
      },
    ],
  };

  if (html) {
    sendGridPayload.content.push({
      type: 'text/html',
      value: sanitizeInput(html),
    });
  }

  const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(sendGridPayload),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`SendGrid API error: ${response.status} - ${errorText}`);
  }

  return { success: true, message: 'Email sent successfully' };
}

async function createPaymentIntent(env, paymentData) {
  const { amount, currency, description, metadata } = paymentData;

  if (!amount || amount < 50) {
    throw new Error('Amount must be at least 50 cents');
  }

  if (!currency || currency.length !== 3) {
    throw new Error('Invalid currency code');
  }

  const params = new URLSearchParams();
  params.append('amount', Math.round(amount));
  params.append('currency', sanitizeInput(currency.toLowerCase()));
  
  if (description) {
    params.append('description', sanitizeInput(description));
  }

  if (metadata && typeof metadata === 'object') {
    Object.keys(metadata).forEach(key => {
      if (key.length <= 40 && typeof metadata[key] === 'string' && metadata[key].length <= 500) {
        params.append(`metadata[${sanitizeInput(key)}]`, sanitizeInput(metadata[key]));
      }
    });
  }

  params.append('automatic_payment_methods[enabled]', 'true');

  const response = await fetch('https://api.stripe.com/v1/payment_intents', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: params.toString(),
  });

  const responseData = await response.json();

  if (!response.ok) {
    throw new Error(`Stripe API error: ${responseData.error?.message || 'Unknown error'}`);
  }

  return {
    success: true,
    paymentIntentId: responseData.id,
    clientSecret: responseData.client_secret,
    amount: responseData.amount,
    currency: responseData.currency,
    status: responseData.status,
  };
}

async function retrievePaymentIntent(env, paymentIntentId) {
  if (!paymentIntentId || typeof paymentIntentId !== 'string') {
    throw new Error('Invalid payment intent ID');
  }

  const sanitizedId = sanitizeInput(paymentIntentId);

  const response = await fetch(`https://api.stripe.com/v1/payment_intents/${sanitizedId}`, {
    method: 'GET',
    headers: {
      'Authorization': `Bearer ${env.STRIPE_SECRET_KEY}`,
    },
  });

  const responseData = await response.json();

  if (!response.ok) {
    throw new Error(`Stripe API error: ${responseData.error?.message || 'Unknown error'}`);
  }

  return {
    success: true,
    id: responseData.id,
    amount: responseData.amount,
    currency: responseData.currency,
    status: responseData.status,
    created: responseData.created,
  };
}

async function handleWebhook(request, env) {
  const signature = request.headers.get('stripe-signature');
  
  if (!signature) {
    throw new Error('Missing Stripe signature');
  }

  const body = await request.text();
  
  const elements = signature.split(',');
  const timestamp = elements.find(e => e.startsWith('t=')).split('=')[1];
  const signatures = elements.filter(e => e.startsWith('v1=')).map(e => e.split('=')[1]);

  const signedPayload = `${timestamp}.${body}`;
  
  const encoder = new TextEncoder();
  const key = await crypto.subtle.importKey(
    'raw',
    encoder.encode(env.STRIPE_WEBHOOK_SECRET),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  
  const signatureBuffer = await crypto.subtle.sign(
    'HMAC',
    key,
    encoder.encode(signedPayload)
  );
  
  const expectedSignature = Array.from(new Uint8Array(signatureBuffer))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');

  const isValid = signatures.some(sig => sig === expectedSignature);

  if (!isValid) {
    throw new Error('Invalid webhook signature');
  }

  const event = JSON.parse(body);

  return {
    success: true,
    eventType: event.type,
    eventId: event.id,
  };
}

async function handleRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  if (request.method === 'OPTIONS') {
    return new Response(null, {
      headers: corsHeaders,
    });
  }

  if (!validateApiKey(request, env)) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json', ...corsHeaders },
    });
  }

  if (request.method === 'POST' && path === '/api/send-email') {
    const emailData = await request.json();
    const result = await sendEmail(env, emailData);
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: { 'Content-Type': 'application/json', ...corsHeaders },
    });
  }

  if (request.method === 'POST' && path === '/api/create-payment-intent') {
    const paymentData = await request.json();
    const result = await createPaymentIntent(env, paymentData);
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: { 'Content-Type': 'application/json', ...corsHeaders },
    });
  }

  if (request.method === 'GET' && path.startsWith('/api/payment-intent/')) {
    const paymentIntentId = path.split('/').pop();
    const result = await retrievePaymentIntent(env, paymentIntentId);
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: { 'Content-Type': 'application/json', ...corsHeaders },
    });
  }

  if (request.method === 'POST' && path === '/api/webhook/stripe') {
    const result = await handleWebhook(request, env);
    return new Response(JSON.stringify(result), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  return new Response(JSON.stringify({ error: 'Not found' }), {
    status: 404,
    headers: { 'Content-Type': 'application/json', ...corsHeaders },
  });
}

export default {
  async fetch(request, env, ctx) {
    try {
      return await handleRequest(request, env);
    } catch (error) {
      console.error('Error:', error);
      
      const statusCode = error.message.includes('Unauthorized') ? 401 :
                        error.message.includes('Invalid') ? 400 :
                        error.message.includes('Not found') ? 404 : 500;

      return new Response(JSON.stringify({ 
        error: error.message,
        success: false 
      }), {
        status: statusCode,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  },
};